+  // (x - 1) & ~(1 << k) == 0 -> x & 1 != 0
+  // When addend is -1 and mask has exactly one zero bit, the solutions to
+  // (x - 1) & mask == 0 are x = 1 and x = 2^k + 1. Both are odd.
+  // With range constraints, this simplifies to x & 1 != 0.
+  if (C.isZero() && Pred == ICmpInst::ICMP_EQ) {
+    Value *X;
+    const APInt *Addend, *Msk;
+    // Try to match: and(add X, -1), mask
+    if (match(And->getOperand(0), m_OneUse(m_Add(m_Value(X), m_AllOnes()))) &&
+        match(And->getOperand(1), m_APInt(Msk))) {
+      // Check if mask has exactly one zero bit
+      APInt NotMask = ~(*Msk);
+      if (NotMask.isPowerOf2()) {
+        unsigned K = NotMask.countr_zero();
+        auto CR = computeConstantRange(X, /*ForSigned=*/false);
+        // Only apply when CR is within [0, 2^(K+1))
+        if (CR.getUpper().ule(APInt::getLowBitsSet(CR.getBitWidth(), K + 1))) {
+          Value *BitCheck = Builder.CreateAnd(X, ConstantInt::get(X->getType(), 1));
+          return new ICmpInst(ICmpInst::ICMP_NE, BitCheck,
+                              ConstantInt::get(X->getType(), 0));
+        }
+      }
+    }
+    // Try commuted: and(mask, add X, -1)
+    if (match(And->getOperand(1), m_OneUse(m_Add(m_Value(X), m_AllOnes()))) &&
+        match(And->getOperand(0), m_APInt(Msk))) {
+      APInt NotMask = ~(*Msk);
+      if (NotMask.isPowerOf2()) {
+        unsigned K = NotMask.countr_zero();
+        auto CR = computeConstantRange(X, /*ForSigned=*/false);
+        if (CR.getUpper().ule(APInt::getLowBitsSet(CR.getBitWidth(), K + 1))) {
+          Value *BitCheck = Builder.CreateAnd(X, ConstantInt::get(X->getType(), 1));
+          return new ICmpInst(ICmpInst::ICMP_NE, BitCheck,
+                              ConstantInt::get(X->getType(), 0));
+        }
+      }
+    }
+  }

   return nullptr;
 }

